import type { CampsiteWithAttributes, CampsiteType, CampsiteStatus, DirectFireType, HammockType, CarAccessType, ToiletType, WaterSourceType, TrashDisposalType, SignalStrength, StarGazingType, BugsLevel, NoiseLevel, Season, LegalStatusType } from "@/types/campsite";

interface SpotInput {
  id: string;
  name: string;
  kana: string;
  slug: string;
  desc: string;
  lat: number;
  lng: number;
  pref: string;
  city: string;
  address: string;
  access: string;
  elev: number | null;
  type: CampsiteType;
  free: boolean;
  price: string;
  url?: string;
  reserveUrl?: string;
  attr: {
    fire: DirectFireType;
    hammock: HammockType;
    sites: number | null;
    car: CarAccessType;
    pet: boolean | null;
    toilet: ToiletType;
    water: WaterSourceType;
    shower: boolean | null;
    trash: TrashDisposalType;
    onsen: number | null;
    docomo: SignalStrength;
    au: SignalStrength;
    sb: SignalStrength;
    solo: boolean;
    family: boolean;
    swim: boolean;
    fish: boolean;
    star: StarGazingType;
    season: Season[];
    bugs: BugsLevel;
    noise: NoiseLevel;
    legal?: LegalStatusType;
    legalNote?: string;
  };
}

function buildSpot(s: SpotInput): CampsiteWithAttributes {
  return {
    id: s.id, name: s.name, name_kana: s.kana, slug: s.slug, description: s.desc,
    latitude: s.lat, longitude: s.lng, prefecture: s.pref, city: s.city, address: s.address,
    access_description: s.access, elevation_m: s.elev, campsite_type: s.type, is_free: s.free,
    price_range: s.free ? "無料" : s.price, official_url: s.url || null, reservation_url: s.reserveUrl || null, status: "active" as CampsiteStatus, source: "manual",
    verified_at: null, created_at: "2024-01-01T00:00:00Z", updated_at: "2024-01-01T00:00:00Z", created_by: null,
    attributes: {
      id: `a${s.id}`, campsite_id: s.id, direct_fire: s.attr.fire, hammock: s.attr.hammock,
      tent_sites: s.attr.sites, car_access: s.attr.car, pet_allowed: s.attr.pet,
      toilet_type: s.attr.toilet, water_source: s.attr.water, shower: s.attr.shower,
      trash_disposal: s.attr.trash, nearest_supermarket_min: null, nearest_convenience_min: null,
      nearest_onsen_min: s.attr.onsen, signal_docomo: s.attr.docomo, signal_au: s.attr.au,
      signal_softbank: s.attr.sb, solo_friendly: s.attr.solo, family_friendly: s.attr.family,
      can_swim: s.attr.swim, fishing: s.attr.fish, star_gazing: s.attr.star,
      best_season: s.attr.season, bugs_level: s.attr.bugs, noise_level: s.attr.noise,
      legal_status: s.attr.legal || (s.type === "managed" ? "authorized" : s.type === "free" ? "public_riverbed" : s.type === "yaei" ? "national_forest" : "unconfirmed"),
      legal_note: s.attr.legalNote || "",
    },
  };
}

